class Egitmen:
    egitmenler = []
    def __init__(self, kullanici_adi, sifre, ad, uzmanlik):
        self.kullanici_adi = kullanici_adi
        self.sifre = sifre
        self.ad = ad
        self.uzmanlik = uzmanlik

class Ogrenci:
    ogrenciler = []
    def __init__(self, kullanici_adi, sifre, ad, email, notlar=None, denemeler=None, ozel_dersler=None):
        self.kullanici_adi = kullanici_adi
        self.sifre = sifre
        self.ad = ad
        self.email = email
        self.notlar = notlar or {}
        self.denemeler = denemeler or []
        self.ozel_dersler = ozel_dersler or []

class Kurs:
    kurslar = []
    def __init__(self, kurs_id, kurs_adi, egitmen, kontenjan, program=None):
        self.kurs_id = kurs_id
        self.kurs_adi = kurs_adi
        self.egitmen = egitmen
        self.kontenjan = int(kontenjan)
        self.kayitli_ogrenciler = []
        self.program = program or []


