class BildirimToast(QFrame):
    def __init__(self, parent, metin):
        super().__init__(parent)
        self.setFixedWidth(340)
        self.setStyleSheet("""
            QFrame {
                background: #1e1e2e;
                border-radius: 14px;
                border: 1.5px solid #34A853;
            }
        """)

        lay = QHBoxLayout(self)
        lay.setContentsMargins(16, 14, 16, 14)
        lay.setSpacing(12)

        ikon = QLabel("🎉")
        ikon.setStyleSheet("font-size: 22px; background: transparent; border: none;")
        ikon.setFixedWidth(28)
        lay.addWidget(ikon)

        msg = QLabel(metin)
        msg.setWordWrap(True)
        msg.setStyleSheet("""
            color: #ffffff;
            font-size: 13px;
            font-weight: 500;
            background: transparent;
            border: none;
        """)
        lay.addWidget(msg)

        self.adjustSize()
        self._yerles(parent)

        # Opaklık animasyonu — fade in
        self.efekt = QGraphicsOpacityEffect(self)
        self.setGraphicsEffect(self.efekt)
        self.efekt.setOpacity(0)
        self.anim_in = QPropertyAnimation(self.efekt, b"opacity")
        self.anim_in.setDuration(350)
        self.anim_in.setStartValue(0)
        self.anim_in.setEndValue(1)
        self.anim_in.setEasingCurve(QEasingCurve.OutCubic)

        self.anim_out = QPropertyAnimation(self.efekt, b"opacity")
        self.anim_out.setDuration(500)
        self.anim_out.setStartValue(1)
        self.anim_out.setEndValue(0)
        self.anim_out.setEasingCurve(QEasingCurve.InCubic)
        self.anim_out.finished.connect(self.deleteLater)

        self.show()
        self.raise_()
        self.anim_in.start()
        QTimer.singleShot(3200, self._kapat)

    def _yerles(self, parent):
        self.adjustSize()
        pw, ph = parent.width(), parent.height()
        w, h = self.sizeHint().width(), self.sizeHint().height()
        self.setFixedWidth(340)
        self.move(pw - 340 - 20, ph - h - 24)

    def resizeEvent(self, e):
        super().resizeEvent(e)

    def _kapat(self):
        self.anim_out.start()

