ARKAPLAN_GORSELI = ""
ARKAPLAN_GORSELI_2 = ""

class GirisSayfasi(QWidget):
    def __init__(self, ana):
        super().__init__()
        self.ana = ana
        self._build()

    def paintEvent(self, event):
        painter = QPainter(self)
        img_data = QByteArray.fromBase64(ARKAPLAN_GORSELI.encode())
        pixmap = QPixmap()
        pixmap.loadFromData(img_data)
        scaled = pixmap.scaled(self.size(), Qt.KeepAspectRatioByExpanding, Qt.SmoothTransformation)
        x = (self.width() - scaled.width()) // 2
        y = (self.height() - scaled.height()) // 2
        painter.drawPixmap(x, y, scaled)
        # Yarı saydam overlay
        painter.fillRect(self.rect(), __import__('PyQt5.QtGui', fromlist=['QColor']).QColor(0, 0, 0, 90))

    def _build(self):
        ana = QVBoxLayout(self)
        ana.setAlignment(Qt.AlignCenter)

        kart = QFrame()
        kart.setFixedSize(440, 550)
        kart.setStyleSheet(f"""
            QFrame {{
                background: white;
                border-radius: 20px;
                border: 1px solid {STIL['border']};
            }}
        """)
        klay = QVBoxLayout(kart)
        klay.setContentsMargins(44, 44, 44, 44)
        klay.setSpacing(14)

        kep = QLabel("🎓")
        kep.setAlignment(Qt.AlignCenter)
        kep.setStyleSheet("font-size: 48px; border: none;")
        klay.addWidget(kep)

        baslik = QLabel("Ders Merkezine\nHoşgeldiniz")
        baslik.setAlignment(Qt.AlignCenter)
        baslik.setStyleSheet(f"font-size: 22px; font-weight: bold; color: {STIL['accent']}; border: none; line-height: 1.3;")
        klay.addWidget(baslik)

        klay.addSpacing(5)

        tip_lay = QHBoxLayout()
        self.btn_ogrenci = QPushButton("Öğrenci")
        self.btn_egitmen = QPushButton("Eğitmen")
        self.btn_ogrenci.setCheckable(True)
        self.btn_egitmen.setCheckable(True)
        self.btn_ogrenci.setChecked(True)

        for btn in [self.btn_ogrenci, self.btn_egitmen]:
            btn.setStyleSheet(f"""
                QPushButton {{
                    background: {STIL['bg']};
                    color: {STIL['text_sub']};
                    border: 1.5px solid {STIL['border']};
                    border-radius: 8px; padding: 8px;
                    font-size: 13px;
                }}
                QPushButton:checked {{
                    background: {STIL['accent']};
                    color: white; border: none;
                }}
            """)
            tip_lay.addWidget(btn)

        self.btn_ogrenci.clicked.connect(lambda: self._tip_sec("ogrenci"))
        self.btn_egitmen.clicked.connect(lambda: self._tip_sec("egitmen"))
        klay.addLayout(tip_lay)

        self.kullanici = QLineEdit()
        self.kullanici.setPlaceholderText("Kullanıcı Adı")
        self.kullanici.setStyleSheet(input_stil())
        klay.addWidget(self.kullanici)

        self.ipucu_kullanici = QLabel("(kullanıcı adı: ogrenci123)")
        self.ipucu_kullanici.setStyleSheet("color: #888; font-size: 11px; border: none; padding-left: 4px;")
        klay.addWidget(self.ipucu_kullanici)

        self.sifre = QLineEdit()
        self.sifre.setPlaceholderText("Şifre")
        self.sifre.setEchoMode(QLineEdit.Password)
        self.sifre.setStyleSheet(input_stil())
        klay.addWidget(self.sifre)

        self.ipucu_sifre = QLabel("(şifre: şifre123)")
        self.ipucu_sifre.setStyleSheet("color: #888; font-size: 11px; border: none; padding-left: 4px;")
        klay.addWidget(self.ipucu_sifre)

        self.hata = QLabel("")
        self.hata.setAlignment(Qt.AlignCenter)
        self.hata.setStyleSheet(f"color: {STIL['danger']}; font-size: 12px; border: none;")
        klay.addWidget(self.hata)

        btn_giris = QPushButton("Giriş Yap")
        btn_giris.setStyleSheet(btn_primary())
        btn_giris.clicked.connect(self.giris_yap)
        klay.addWidget(btn_giris)

        ana.addWidget(kart)
        self.aktif_tip = "ogrenci"

    def _tip_sec(self, tip):
        self.aktif_tip = tip
        self.btn_ogrenci.setChecked(tip == "ogrenci")
        self.btn_egitmen.setChecked(tip == "egitmen")
        if tip == "ogrenci":
            self.ipucu_kullanici.setText("(kullanıcı adı: ogrenci123)")
            self.ipucu_sifre.setText("(şifre: şifre123)")
        else:
            self.ipucu_kullanici.setText("(kullanıcı adı: admin123)")
            self.ipucu_sifre.setText("(şifre: Admin)")

    def giris_yap(self):
        kullanici = self.kullanici.text().strip()
        sifre = self.sifre.text().strip()
        if not kullanici or not sifre:
            self.hata.setText("Tüm alanları doldurun!")
            return
        if self.aktif_tip == "ogrenci":
            for o in Ogrenci.ogrenciler:
                if o.kullanici_adi == kullanici and o.sifre == sifre:
                    self.ana.ogrenci_paneli_ac(o)
                    return
            self.hata.setText("Kullanıcı adı veya şifre hatalı!")
        else:
            for e in Egitmen.egitmenler:
                if e.kullanici_adi == kullanici and e.sifre == sifre:
                    self.ana.egitmen_paneli_ac(e)
                    return
            self.hata.setText("Kullanıcı adı veya şifre hatalı!")

