class AnaPencere(QMainWindow):
    def __init__(self):
        super().__init__()
        self.setWindowTitle("🎓 Ders Merkezi Yönetim Sistemi")
        self.setMinimumSize(1200, 750)
        self.resize(1300, 800)
        self.db_baslat()
        self._varsayilan_kullanici_ekle()
        self.veri_yukle()
        self.stack = QStackedWidget()
        self.setCentralWidget(self.stack)
        self.giris_sayfasi_ac()

